parsed.api_descriptions:
API_name: nchu_course_search_by_keyword
Description:
{
  "description": "依關鍵字搜尋中興大學課程資料庫中的課程。",
  "required_parameters": [
    {
      "name": "keyword",
      "type": "STRING",
      "description": "Search keyword"
    }
  ],
  "optional_parameters": [
    {
      "name": "limit",
      "type": "NUMBER",
      "description": "Maximum number of results to return (default: 10)",
      "default": 10
    },
    {
      "name": "search_fields",
      "type": "STRING",
      "description": "Comma-separated fields to search in (default: 科目名稱,上課教師,開課單位,系所名稱,備註)",
      "default": null
    },
    {
      "name": "case_sensitive",
      "type": "BOOLEAN",
      "description": "Whether search is case sensitive (default: False)",
      "default": false
    },
    {
      "name": "include_syllabus_search",
      "type": "BOOLEAN",
      "description": "Also search in syllabus content (課程簡述, 課程目標, 每週授課內容, etc.) (default: False)",
      "default": false
    },
    {
      "name": "include_syllabus_in_result",
      "type": "BOOLEAN",
      "description": "Include full syllabus in results (default: False)",
      "default": false
    },
    {
      "name": "semester",
      "type": "STRING",
      "description": "Semester code (e.g., \"1142\" for 113-2). If not specified, uses the latest semester.",
      "default": null
    }
  ]
}

